+                params: None,
+                parse_dates: Some(vec!["ts".to_owned()]),
+                coerce_float: false,
+                dtype: Some(dtype_map),
+            },
+        )
+        .expect("read with parse_dates priority");
+        let col = frame.column("ts").expect("ts");
+        assert_eq!(col.dtype(), DType::Utf8);
+    }
